def pca_transform(df):
    pca = PCA(n_components=1)  # Reduce to 1 principal component
    principal_components = pca.fit_transform(df.drop(columns = ['X Coordinate', 'Y Coordinate']))
    
    #pca_df = pd.DataFrame(data=principal_components, columns=['Marker'])

    #Create new dataframe with just the marker.
    # pca_df = df[['X Coordinate', 'Y Coordinate']]
    pca_df = df[['X Coordinate', 'Y Coordinate']].copy()         #---- Change one line, get rid of an annoying warning.
    pca_df['Marker'] = pd.DataFrame(data=principal_components)

    #Re-scale PCA values to between 0-1, to get rid of negative values.
    
    #create the numpy array
    x = np.array(pca_df['Marker'])
    #reshape array so that it works with sklearn
    x = x.reshape(-1, 1)
    #normalize all values to be between 0 and 1
    x_norm = pre.MinMaxScaler().fit_transform(x)
    #unpack this [1,1] matrix back into a list
    x_nl = []
    for i in x_norm:
        x_nl.append(i[0])
    #replace the 'Marker' column with these normalized values
    pca_df['Marker'] = x_nl

    return(pca_df)

# %% ../white_matter_module_2_DEVELOPMENT_contdx5_3_12_12_25_backup-Mult_Complex_Infill.ipynb #890ee4e0-0b33-4f1b-ab22-75fb48d31af4
def closest_val(value_list, target_value):
    # The key function tells min() *how* to compare the items.
    # It calculates the absolute difference: |x - target_value|
    return min(value_list, key=lambda x: abs(x - target_value))

