def make_quant(white_matter_df, q_factor):
    #q_factor needs to be an integer here:
    if q_factor.is_integer():
        #Make sure it's in integer format.
        q_factor = int(q_factor)
    else:
        print("ERROR! 'q_factor' must be a whole number.")

    #Determine the range along which we need to quantize.
    max_val = max(max(white_matter_df['X Coordinate']),max(white_matter_df['Y Coordinate']))
    #We set the limit of the range to be greater than the maximum possible value in either axis, and add one more interval just in-case it rounds down.
    lim = round(max_val/q_factor)*q_factor + q_factor
    #Create list of possible values. Not inclusive of the top-most value.
    vals = list(range(0, lim, q_factor))
    #And, we output the midpoint pf each range,
    midpoints = [item + (q_factor/2) for item in vals]
    #-----
    # This is very important. If the number possible quantized points along a range = n,
    # Then the number midpoint = n-1!
    #-----

    #Finally, we use the 'closest_val' function above, to quantize all the values here:
    X_quant = []
    for i in white_matter_df['X Coordinate']:
        X_quant.append(closest_val(midpoints, i))
        
    white_matter_df['X_quant'] = X_quant
    
    Y_quant = []
    for i in white_matter_df['Y Coordinate']:
        Y_quant.append(closest_val(midpoints, i))

    white_matter_df['Y_quant'] = Y_quant
    
    return(max_val, lim, midpoints, white_matter_df)

