def make_white_matter_df (input_df, mkr='+', q_factor = 100, bin_thresh=None):

    #Apply the dimensionality reduction technique
    white_matter_df = pca_transform(input_df)
    
    #In case the index is duplicated.
    if 'Unnamed: 0' in white_matter_df.columns:
        white_matter_df = white_matter_df.drop('Unnamed: 0', axis=1)

    #--------------
    #Quantized by whatever factor the user provides.
    # white_matter_df['X_quant'] = round(white_matter_df['X Coordinate']/q_factor)*q_factor
    # white_matter_df['Y_quant'] = round(white_matter_df['Y Coordinate']/q_factor)*q_factor

    max_val, lim, midpoints, white_matter_df = make_quant(white_matter_df, q_factor=q_factor)
    #--------------

    #This makes a new dataframe of just the quantized positions, which  should be much smaller than the original.
    #It will sum together the marker expression for these points.
    #https://stackoverflow.com/questions/38985053/groupby-and-sum-only-one-column
    exp_bin_df = white_matter_df.groupby(['X_quant','Y_quant'], as_index=False)['Marker'].sum()
    exp_bin_df  

    #Now to convert marker to binary based on the mean expression.

    #--First, we scale the expression of the marker column by mean expression for all quantized positions.
    #--This makes the resulting graph easier to interpret.
    mn = statistics.mean(exp_bin_df['Marker'].values)
    # print('mn is:', mn)
    
    exp_bin_df['Marker'] = exp_bin_df['Marker']/mn
    # print('exp_bin_df is:', exp_bin_df.head())

    #Helpful to have in a list format
    exp = exp_bin_df['Marker'].values
    # print('exp is:', exp[:5])

    #--And then, we deploy *Otsu's Method* to determine an appropriate cutoff value for binarization:
    # https://en.wikipedia.org/wiki/Otsu%27s_method
    # Code is adapted from: https://docs.opencv.org/3.4/d7/d4d/tutorial_py_thresholding.html

    #values must be scaled from 0-255 for uint8 format, which is what cv2 requires.
    m_kr = exp/exp.max()*255
    # print('m_kr is:', m_kr[:5])
    
    #we preserve this scale factor because we're going to neeed it later...
    factor = exp.max()/255
    # print("Scale factor is:", factor)
    
    #Convert to a list
     #(Already did that...)

    #Convert to numpy array
    matr = np.array(m_kr)
    # print('matr is:', matr[:5])
    
    #Now convert to uint8 format
    matr = matr.astype(np.uint8)
    # print('matr is:', matr[:5])

    #And now we can apply cv2's histogram generating function.
    hist = cv.calcHist([matr],[0],None,[256],[0,256])
    
    #Apply Otsu's method to the newly generated histogram:
    hist_norm = hist.ravel()/hist.sum()
    Q = hist_norm.cumsum()
    bins = np.arange(256)
    fn_min = np.inf
    thresh = -1
    for i in range(1,256):
        p1,p2 = np.hsplit(hist_norm,[i]) # probabilities
        q1,q2 = Q[i],Q[255]-Q[i] # cum sum of classes
        if q1 < 1.e-6 or q2 < 1.e-6:
            continue
        b1,b2 = np.hsplit(bins,[i]) # weights
        # finding means and variances
        m1,m2 = np.sum(p1*b1)/q1, np.sum(p2*b2)/q2
        v1,v2 = np.sum(((b1-m1)**2)*p1)/q1,np.sum(((b2-m2)**2)*p2)/q2
        # calculates the minimization function
        fn = v1*q1 + v2*q2
        if fn < fn_min:
            fn_min = fn
            thresh = i

    print()

    #Finally, we take "thresh", which is our threshold on the 0-255 scale, and reconstitute it with our scale factor:
    otsu_threshold = thresh*factor
    print("Via Otsu's Method for bimodal distributions, we binarize expression at x", round(otsu_threshold, 3), "of the mean expression value.")

    # ----------
    # And if the user has not specified a value for 'bin_thresh', then we use this value generated by Otsu's method:
    if bin_thresh == None:
        bin_thresh = otsu_threshold
    # ----------

    #And we make the new column accordingly:
    # -------
    # Using 'bin_thresh' rather than 'otsu_threshold'
    # -------
    
    #Recall that if our marker is negative, the coding scheme is flipped. 
    if mkr == '+' :
      exp_bin_df['Binarized_Marker'] = np.where(exp_bin_df['Marker'] > bin_thresh, 1, 0)  
    #Because a negative marker says: "This is not an oligodendrocyte." eg. Slc17a6
    elif mkr == '-' :
      exp_bin_df['Binarized_Marker'] = np.where(exp_bin_df['Marker'] > bin_thresh, 0, 1) 
    else:
      print("INVALID MARKER! Must be either '+' or '-'.")

    #We duplicate this column just prior to the merge, so that it's also copied to the 'white_matter_df' table.
    #Just for clarity, we'll leave it in the original table as well.
    exp_bin_df['Position_ID'] = exp_bin_df.index

    #Finally, we add the binarized expression value back to the original dataframe.
    white_matter_df = pd.merge(white_matter_df, exp_bin_df, how="right", on=["X_quant", "Y_quant"])
    white_matter_df = white_matter_df.drop(columns={'Marker_y'})
    white_matter_df = white_matter_df.rename({'Marker_x':'Marker'}, axis=1)
    white_matter_df
    
    print()
    print("Note: The argument 'q_factor' is used to bin points together. Points which share the same 'X_quant' and 'Y_Quant' will have their expression of the marker summed together for that particular position, 'Position_ID'. Binarized expression is calculated for each position. The fewer positions, the less time the annotation process will take.")

    
    #Potentially useful in deciding whether to adjust 'q_factor':
    X_set = set(white_matter_df['X_quant'].values)
    Y_set = set(white_matter_df['Y_quant'].values)
    
    print()
    print('q_factor=', q_factor,', Maximum number of quantized positions= ', len(X_set)*len(Y_set),',', len(X_set), 'x', len(Y_set))

    print('Actual number of quantized positions:',len(exp_bin_df.index))

    return (white_matter_df, exp_bin_df, otsu_threshold, bin_thresh)

