def neighbors(focus, df, rad=100):

  #"Cutting out" a square search region to reduce the time the algorithm takes.
  #This filters for all points within the given radius in either the X or Y axis, producing a square "cut-out"

  X = df.iloc[focus]['X_quant']
  Y = df.iloc[focus]['Y_quant']

  df_filt = df[(df['X_quant']>(X-rad)) & (df['X_quant']<(X+rad))]
  df_filt = df_filt[(df_filt['Y_quant']>(Y-rad)) & (df_filt['Y_quant']<(Y+rad))]

  #Filter for points which meet the radius requirement, and simply output their IDs.
  #Recall that we want a circular region around the given point.

  n_list = []
    
  for i in df_filt.values:
    # print (i[0], i[1], i[4])    

    i = list(i)
    X_ = float(i[0])
    Y_ = float(i[1])
      
    dist = (X-X_)**2 + (Y-Y_)**2
    if dist <= rad**2:
      #These are indicies in the dataframe. Must be integer.
      n_list.append(int(i[4]))

  return n_list

