def iter_smooth(df, raw_df, q_factor):
    #Convert dataframe into a 2D numpy array for faster processing.
    pivot_table, matr = mk_outline(df, q_factor)

    #Iteratively apply the "blur_smooth" function
    diffs = 1 # --To start the loop.
    count = 0
    
    while diffs != 0 & count<20:
        result, diffs = blur_smooth(pivot_table)
        #Update for the next iteration of the loop.
        pivot_table =result

    #Reflect the final matrix result in the X-Y axis
    result = result.T

    #Start building up the column to replace the current 'Smooth_Mask' column
    #This column shows whether a point should be allowed to remain in 'exp_bin_df'
    mask = []
    for i in result:
      for j in i:
        mask.append(j)

    #Update the column
    matr['Smooth_Mask'] = mask

    # --Recall from the previous version of this function:
    # We filter out any points in 'white_matter_df' corresponding to dropped positions.
    # So that there are no points in that df corresponding to positions that no longer exist.
    
    #Let's make a list of all the points for which 'Mask' = 0. We'll want to filter 'white_matter_df' for these points.
    matr_dropped = list(matr[matr['Smooth_Mask'] == 0]['Position_ID'])

    #And let's filter these positions out of 'white_matter_df'. Note that in this table, 'Position_ID' is NOT the index.
    raw_df = raw_df[~raw_df['Position_ID'].isin(matr_dropped)]
    
    #And now we drop all points which are labelled as '0' in the mask.
    matr = matr[matr['Smooth_Mask'] == 1]
    #And we drop this column, since we no longer need it:
    matr = matr.drop(columns=['Smooth_Mask'])

    #Return the newly filtered version of 'exp_bin_df'
    df = matr.copy()
    
    return (df, raw_df)

