def blur_smooth_2(pivot_table):
    #Make the vector of zeroes.
    n = pivot_table.shape[0]

    # --------------------
    #Making the vectors we're going to use to "shift" the matrix.
    n_arr = [math.nan] * n
    n_arr = np.array(n_arr)
    #---------------------
    
    n_arr = n_arr.reshape(1, n)
    n_arr_2d = n_arr.reshape(n, 1)

    #And now we apply the 8 transformations:
    pivot_table_1_0 = np.concatenate([n_arr, pivot_table[0:-1, :]], axis=0)
    pivot_table_m1_0 = np.concatenate([pivot_table[1:, :], n_arr], axis=0)
    pivot_table_0_1 = np.concatenate([n_arr_2d, pivot_table[:, 0:-1]], axis=1)
    pivot_table_0_m1 = np.concatenate([pivot_table[:, 1:], n_arr_2d], axis=1)
    
    pivot_table_1_1 = np.concatenate([n_arr, pivot_table_0_1[0:-1, :]], axis=0)
    pivot_table_m1_1 = np.concatenate([pivot_table_0_1[1:, :], n_arr], axis=0)
    pivot_table_1_m1 = np.concatenate([n_arr, pivot_table_0_m1[0:-1, :]], axis=0)
    pivot_table_m1_m1 = np.concatenate([pivot_table_0_m1[1:, :], n_arr], axis=0)

    #Stack these matricies and sum across this new dimension:
    pivot_matrix = np.stack([pivot_table_1_0, pivot_table_m1_0, pivot_table_0_1, pivot_table_0_m1, 
                             pivot_table_1_1, pivot_table_1_m1, pivot_table_m1_1, pivot_table_m1_m1], axis=0)

    pivot_sum = np.sum(pivot_matrix, axis=0)
    #Note: We use 'nanmean' instead of 'average' because we want the 'nan' values to be ignored when calculating the mean expression.
    with warnings.catch_warnings(action="ignore"): # --Supresses the warning we get when an empty slice is encountered.
        pivot_avg = np.nanmean(pivot_matrix, axis=0)
    # pivot_avg = np.average(pivot_matrix, axis=0)

    #The aim is to filter out "1"  points with fewer than 3 "1" neighbours.
    #1. We start by making the binary filter layer
    # pivot_sum_bin = (pivot_sum > 2)*1
    #2. And apply it:
    # result = pivot_sum_bin*pivot_table

    # result = pivot_sum
    result = pivot_avg
    
    return (result, pivot_matrix)

