def solidify(pivot_table):

    #Since we need to remake these objects everytime we run this function,
    # it makes sense to nest this function into 'solidify':
    result, pivot_matrix = blur_smooth_2(pivot_table)
    
    # 1. If a point has fewer that 3 neighbours, we automatically impute it as zero.
    nan_matrix = np.isnan(pivot_matrix).sum(axis=0)
    nan_matrix_bin = 1-(nan_matrix > 5)*1
    # 2. If a point is "0", and averages greater than "5/8" in its immediate neighbourhod, we flip it to "1".
    inv_pivot = 1 - pivot_table
    zero_layer = inv_pivot*((result >= (5/8))*1)
    # 3. If a point is "1", and averages greater than 7/8 zeroes in its immediate neighbourhood, we flip it to 0.
    inv_result = 1 - result
    one_layer = pivot_table*((inv_result >= (7/8))*1)

    #Finally, we apply all three layers and return the result:
    pivot_table_new = pivot_table*nan_matrix_bin + zero_layer - one_layer

    #-------------------- Edit: 2.27.26
    pivot_table_new = abs(pivot_table_new)
    #--------------------
    
    #This method only works on matricies of integers.
    #Which is a problem, because 'nan' is technically a float value.;=
    with warnings.catch_warnings(action="ignore"): # --We also need it to ignore the nans, and not give use an annoying warning everytime.
        diffs = np.sum(pivot_table_new.astype(int) != pivot_table.astype(int))
    print('flip count:', diffs)

    return (pivot_table_new, diffs)

