def infill_mask(df, q_factor):
    pivot_table, matr = mk_outline_2(df, q_factor)
    #Recall that 'solidify' now contains 'blur_smooth_2'
    diffs = 1
    count = 0
    max_iterations = 20
    
    #Iteratively apply the function to solidify the outline of the target region
    while diffs != 0 and count < max_iterations:  #--Edit: 2.27.26 
        #('and' is not the same as "&"! This causes the loop to ignore the second condition and run forever!!!)
        pivot_table_new, diffs = solidify(pivot_table)
        #Update for the next iteration of the loop.
        pivot_table = pivot_table_new
        count += 1
        #----------------------------------------------
        #Outputs a plot of each step, so we can visualize progress and identify bugs.
        # plt.imshow(pivot_table, origin="lower", interpolation='nearest')
        # plt.colorbar()
        # plt.show()
        #----------------------------------------------
    
    #Reflect the final matrix result in the X-Y axis
    pivot_table = pivot_table.T
    
    #Start building up the column to replace the current 'Smooth_Mask' column
    #This column shows whether a point should be allowed to remain in 'exp_bin_df'
    mask = []
    for i in pivot_table:
      for j in i:
        mask.append(j)
    
    #Update the column
    matr['Mask'] = mask  

    #Finally, we merge the new values (and return the object):
    output = df[['X_quant', 'Y_quant', 'Marker', 'Binarized_Marker', 'Position_ID']].merge(
        matr[['X_quant', 'Y_quant', 'Mask']], on=['X_quant', 'Y_quant'], how='left')

    #Update the value of df (Redundant, yes. But I like to be clear about the flow of logic here.
    df = output.copy()
    
    return (df)

