def get_midpoints(df, q_factor_s):
    #Determine the range along which we need to quantize.
    max_val = max(max(df['X_quant']),max(df['Y_quant']))
    #We set the limit of the range to be greater than the maximum possible value in either axis, and add one more interval just in-case it rounds down.
    lim = round(max_val/q_factor_s)*q_factor_s + q_factor_s
    #Create list of possible values. Not inclusive of the top-most value.
    vals = list(range(0, lim, q_factor_s))
    #And, we output the midpoint pf each range,
    midpoints = [item + (q_factor_s/2) for item in vals]
    #-----
    # This is very important. If the number possible quantized points along a range = n,
    # Then the number midpoint = n-1!
    #-----
    
    return(midpoints)

# %% ../white_matter_module_2_DEVELOPMENT_contdx5_3_12_12_25_backup-Mult_Complex_Infill.ipynb #092b48f9-5f13-4f92-983f-99dbd348e2c4
def make_scaled_df(df, q_factor, scale):
    
    q_factor_s = q_factor*scale
    
    #MUST make a copy of 'df', otherwise all these changes will be commuted back to the original object.
    df_ = df.copy()
    
    #Quantized by whatever factor the user provides.
    # df_['X_quant'] = round(df_['X_quant']/q_factor_s)*q_factor_s
    # df_['Y_quant'] = round(df_['Y_quant']/q_factor_s)*q_factor_s

    # ---------------------------------------------------------
    midpoints = get_midpoints(df, q_factor_s)

    #And as usual, we are required to build this up as a vector:
    X_vals = []
    for i in df_['X_quant']:
        X_vals.append(closest_val(midpoints, i))
        
    Y_vals = []
    for i in df_['Y_quant']:
        Y_vals.append(closest_val(midpoints, i))
    
    df_['X_quant'] = X_vals
    df_['Y_quant'] = Y_vals
    # ----------------------------------------------------------

    #And collapse the dataframe based on these values.
    df_out = df_.groupby(['X_quant','Y_quant'], as_index=False)['Mask'].sum()

    #Re-binarize so that all points with non-zero expression are labelled "1":
    df_out['Bin_Mask'] = np.where(df_out['Mask'] > 0, 1, 0)
    #And to avoid confusion, let's make the format of this dataframe make sense. Firstly, let's rename 'Mask' to 'Marker'
    df_out['Marker'] = df_out['Mask']
    #The column of binarized expression needs to be called 'Binarized_Marker', as this is what the infill function is looking for.
    df_out['Binarized_Marker'] = df_out['Bin_Mask']
    #Delete the duplicate columns.
    df_out = df_out.drop(columns=['Mask','Bin_Mask'])
    #We also need to output our indicies to the 5th(4-indexed) column, or 'infill_mask' will throw an error.
    df_out['Position_ID'] = df_out.index

    #And now we trim the original-length dataframe (with now inaccurate positions) into a correspondence table.
    df_ = df_[['X_quant', 'Y_quant']]
    #And let's add the idex in the new table that corresponds to a particular position.
    # index_df = df_out[['X_quant', 'Y_quant']]
    index_df = df_out[['X_quant', 'Y_quant']].copy() #--- Hopefully this gets rid of the annoying warning.
    index_df['Index'] = index_df.index
    #merge onto df, to add indicies.
    df_ = pd.merge(df_, index_df, on=['X_quant', 'Y_quant'], how='left')
    #We now drop the (quantized) X and Y positions from 'df_', given that these are not accurate to the
    #high resolution points. So, they'll only cause confusion...
    df_ = df_[['Index']]

    return (df_, df_out)

