def infill_mask_complex(exp_bin_df, q_factor, scale=2):

    print("Applying high-resolution infill mask: ")
    #We start off by applying the infill mask to the higher resolution dataset
    high_res_mask_df = infill_mask(exp_bin_df, q_factor)

    #If the user enters a single number, then we'll need to convert it to a list in order for the iterable to work:
    if type(scale)==int or type(scale)==float:
        scale_lis = []
        scale_lis.append(scale)
        
        scale = scale_lis

    #We'll also need to rationalize the output of 'relief' if generating it multiple times.
    #To achieve this: We start with a blank object in which we label everything as 'unaffected'.
    lis_1 = ['Unaffected']*len(exp_bin_df)
    lis_1 = pd.DataFrame(lis_1)
    #This first column in the dataframe will be labeled 'lis_1[0]'. This is what we'll compare our
    #relief mak to, everytime it's generated.

    for scale_n in scale:
        
        #We then make a new version of this quantized and masked dataframe, using the 'q_factor' provided and the 'scale' provided.
        #The table we call 'indicies' is what maps this low-res dataframe onto the high-res one.
        indicies, low_res_df = make_scaled_df(high_res_mask_df, q_factor, scale_n)
    
        print("Applying low-resolution filter mask: ")
        #Apply the function 'infill_mask' to this new lower resolution dataframe, to remove floating points/clusters.
        qf = q_factor #recall we must provide an accurate distance between points for this function.
        low_res_df = infill_mask(low_res_df, q_factor = (qf*scale_n))
    
        #And now we set about merging the two masks and outputing the results:
    
        #We need to make an index column to merge on.
        low_res_df['Index'] =low_res_df.index
        #And merge only the columns we care about
        indicies = pd.merge(indicies, low_res_df[['Mask','Index']], on=['Index'], how='left')
        #Ensure that 'Mask' is an integer column.
        indicies['Mask'] = indicies['Mask'].astype(int)
    
        #Now that we have our indicies, we can apply the new mask back to the higher resolution data. 
        conflict_df = pd.merge(high_res_mask_df, indicies[['Mask']], left_index=True, right_index=True, how='inner')
        #Finally, we rationalize the two masks, by taking their overlap.
        conflict_df['Mask'] = np.where((conflict_df['Mask_x'] == 1) & (conflict_df['Mask_y'] == 1), 1, 0)
    
        #Use seaborn to display to the user which points have been retained/removed, so they can adjust as needed.
        conditions = [
            (conflict_df['Mask'] == 1),
            (conflict_df['Mask_x'] == 1) & (conflict_df['Mask'] == 0),
            (conflict_df['Mask_x'] == 0) & (conflict_df['Mask'] == 0)
        ]
        
        values = ['Retained', 'Removed', 'Unaffected']
        
        # Apply conditions to create a new column:
        conflict_df['Relief'] = np.select(conditions, values)
    
        #Instead of making the plot within this function, we output 'Relief' as a second object, so that we can plot it using the same parameters as all our other graphs in 'wm_annot'.
        relief = conflict_df['Relief']
        
        #And let's drop the conflicting 'Mask' columns, now that we no longer need them.
        conflict_df = conflict_df.drop(columns=['Mask_x', 'Mask_y', 'Relief'])

        #------------------------------------------------------------------------------
        #And now we compare this 'relief' list to the current version that we have saved.

        #Add it to the dataframe:
        lis_1[1] = relief

        #And our conditions are to remove any points removed in by our new mask.
        conditions = [
            (lis_1[0] == 'Unaffected') & (lis_1[1] == 'Unaffected'),
            (lis_1[0] == 'Unaffected') & (lis_1[1] == 'Retained'), #Only apllicable on the first run..
            (lis_1[0] == 'Unaffected') & (lis_1[1] == 'Removed'), #...when the reference is blank.
            #Only points retained across masks should remain.
            (lis_1[0] == 'Retained') & (lis_1[1] == 'Retained'),
            #All others should be filtered out.
            (lis_1[0] == 'Retained') & (lis_1[1] == 'Removed'),
            (lis_1[0] == 'Removed') & (lis_1[1] == 'Retained'),
            (lis_1[0] == 'Removed') & (lis_1[1] == 'Removed')
        ]
        
        values = ['Unaffected', 'Retained', 'Removed',  'Retained', 'Removed','Removed', 'Removed']
        
        # Apply conditions to create a new column:
        lis_1['Relief'] = np.select(conditions, values)

        #Return the latest version of 'relief' to the user:
        relief = lis_1['Relief']
        #And, reset our dataframe in case we need it again:
        lis_1 = pd.DataFrame(lis_1['Relief'])
        lis_1 = lis_1.rename(columns={'Relief': 0})
        #-----------------------------------------------------------------------------

    #And to be sure we've filtered out all the points that need to be removed from our final output dataframe:
    #This line suppresses the warning we might get due to the boolean.
    pd.set_option("future.no_silent_downcasting", True)
    lis_1['Bool'] = lis_1[0]=='Removed'
    lis_1['Bool'] = lis_1['Bool'].replace({True: 0, False: 1})
    #Notice we've inverted this, so that 'Remove' values are all coded as zero. Anything else is one.
    conflict_df['Mask'] = conflict_df['Mask']*lis_1['Bool']
    #And now any "1" value in our mask that is to be removed is multiplied by zero, removing it.

    #But now, we need to be absolutely sure that the resulting column is *numeric* datatype. Not *object*! Or it will break something downstream.
    # Step 1: Convert to numeric safely
    conflict_df['Mask'] = pd.to_numeric(conflict_df['Mask'], errors='coerce')  # Non-numeric -> NaN
    # Step 2: Convert to integer
    conflict_df['Mask'] = conflict_df['Mask'].astype(int)  # Pandas nullable integer type

    #And return the final mask.
    return (conflict_df, relief)

