def d_scale(df, K = 3, power=2):

    #As usual, to prevent these edits from being transmitted back to the original object:
    df_ = df.copy()

    # 2. Calculate k-NN density metric (Distance to the Kth nearest neighbor)
    # Density is INVERSELY proportional to this distance (r_k).
    # We fit the model and find the distance to the Kth neighbor (k=K).
    nn = NearestNeighbors(n_neighbors=K).fit(df_.iloc[:, [0,1]])
    
    # The output is (distances, indices). We only need the distances.
    # distances[:, K-1] is the distance to the Kth nearest neighbor (since distances are sorted).
    distances, indices = nn.kneighbors(df_.iloc[:, [0,1]])
    df_['kth_neighbor_distance'] = distances[:, K-1]
        
    #Average values across this 'density' column:
    #We also include this 'power' scaling factor, which we can fine-tune later.
    dist = (statistics.mean(df_['kth_neighbor_distance']))

    #To make a long story short, I've decided to manually set these, because the math is really confusing:
    if dist<20:
        d_scale = 5
    elif dist<60:
        d_scale = 10
    elif dist<80:
        d_scale = 15
    elif dist<120:
        d_scale = 20
    elif dist<160:
        d_scale = 40
    elif dist<250:
        d_scale = 60
    elif dist<400:
        d_scale = 80
    else:
        d_scale = 100

    # print(df)
    # print(round(statistics.mean(df['kth_neighbor_distance']), 3), round(d_scale, 3))
    
    return(d_scale)
#--------------------------------------------

