def mk_tile_plot (df, q_factor, theme='viridis', title_message='[your_title_here]'):
    # 1. Start by filling in the background.
    area = max(max(exp_bin_df['X_quant']), max(exp_bin_df['Y_quant'])) + q_factor/2

    # Create a blank dataframe with all possible quantized positions,
    matr = []
    r = int(area/q_factor)

    # ---
    # Recall that we need the midpoint of each range. Hence, the complicated math...
    # ---
    for i in range (0, r+1):
      for j in range (0, r+1):
          matr.append([float((i+0.5)*q_factor), float((j+0.5)*q_factor)])

    #Convert to dataframe:
    matr = pd.DataFrame(matr, columns = ['X_quant', 'Y_quant'])
    
    # And merge it with our existing dataframe, filling in any missing points as "2" (background).
    matr = pd.merge(matr, exp_bin_df, on=['X_quant', 'Y_quant'], how='left')
    #And let's fill in blank positions in the mask.
    matr['Mask'] = matr['Mask'].fillna(2).astype(int)  

    #2. Convert to pivot table.
    pivot_table = matr.pivot(index='Y_quant', columns='X_quant', values='Mask')
    #Note that the columns seem backwards here, but that's necessary for it to render the way we want it to.

    # 3. Create the Heatmap (Tile Plot)
    plt.figure(figsize=(8, 6))
    ax = sns.heatmap(
        pivot_table,
        cmap=theme, # Colormap to use (e.g., 'viridis', 'coolwarm', 'YlGnBu')
        cbar=False,      # Show the color bar (legend for the third variable)
        linewidths=.5,  # Space between tiles
        linecolor='white',
        alpha=0.6
    )
    
    #Set limits to correspond to our actual data:
    ax.set_xlim(0, (max(exp_bin_df['X_quant'])/q_factor)+1)
    ax.set_ylim(0, (max(exp_bin_df['Y_quant'])/q_factor)+1)
  
    # Set the title and labels
    plt.title(title_message)
    
    plt.show()


