def mk_pivot (df, q_factor, z='Mask', fill='blank'):
    # 1. Start by filling in the background.
    area = max(max(df['X_quant']), max(df['Y_quant'])) + q_factor/2

    # Create a blank dataframe with all possible quantized positions,
    matr = []
    r = int(area/q_factor)

    for i in range (0, r+1):
      for j in range (0, r+1):
          matr.append([float((i+0.5)*q_factor), float((j+0.5)*q_factor)])
    
    matr = pd.DataFrame(matr, columns = ['X_quant', 'Y_quant'])
    
    # And merge it with our existing dataframe:
    matr = pd.merge(matr, df, on=['X_quant', 'Y_quant'], how='left')
    #And let's fill in blank positions in the mask with a defined value.
    #Except that for the first figure, it's better to leave it as-is/
    if fill=='blank':
        pass
    else:
        matr[z] = matr[z].fillna(fill).astype(int)

    #2. Convert to pivot table.
    pivot_table = matr.pivot(index='Y_quant', columns='X_quant', values=z)
    #Note that the columns seem backwards here, but that's necessary for it to render the way we want it to.

    return(pivot_table)


