# %% ../white_matter_module_2_DEVELOPMENT_contdx5_3_12_12_25_backup-Mult_Complex_Infill.ipynb #2bebdada-121d-44e5-9011-f17dbdf160f9
def mk_pivot_table(df,q_factor):
    #To impute the background, make a blank matrix of all possible positions, given
    # 1. Start by filling in the background.
    area = max(max(df['X_quant']), max(df['Y_quant'])) + q_factor/2
            
    matr = []
    r = int(area/q_factor)

    #We later trim this mask to the right size, so let's focus on making sure we have enough space.
    #Notice that we've applied 'iter_smooth', wo we can't quite trust the current size of our dataframe.
    for i in range (0, r+20):
      for j in range (0, r+20):
          matr.append([float((i+0.5)*q_factor), float((j+0.5)*q_factor)])
    
    matr = pd.DataFrame(matr, columns = ['X_quant', 'Y_quant'])
    
    #Add an empty "mask" to mark all the background points.
    # matr['Mask'] = 2
    
    #matr
    
    matr = pd.merge(matr, df, on=['X_quant', 'Y_quant'], how='left')
    #And let's fill in blank positions in the mask.
    matr['Mask'] = matr['Mask'].fillna(2)

    #2. Convert to pivot table.
    pivot_table = matr.pivot(index='Y_quant', columns='X_quant', values='Mask')
    #Note that the columns seem backwards here, but that's necessary for it to render the way we want it to.

    #And convert to Numpy array:
    pivot_table = np.array(pivot_table)

    #plt.imshow(matr_2d, interpolation="nearest", origin="lower")
    plt.imshow(pivot_table, origin="lower")
    plt.colorbar()
    plt.show()

    return(pivot_table)

# %% ../white_matter_module_2_DEVELOPMENT_contdx5_3_12_12_25_backup-Mult_Complex_Infill.ipynb #e38b509b-a6f5-45b2-9153-f54f2e1f00ba
def matr_expand(pivot_table, q_factor, factor):
    print('factor: ', factor)
    print('final resolution: ', q_factor/factor)
    
    expanded_matrix = np.kron(pivot_table, np.ones((factor, factor)))
    
    print('shape of matrix',expanded_matrix.shape)
    
    return(expanded_matrix)

# %% ../white_matter_module_2_DEVELOPMENT_contdx5_3_12_12_25_backup-Mult_Complex_Infill.ipynb #6155dfd4-8cd4-4241-8123-4a11a1adea9e
import cv2
import tifffile as tf

# %% ../white_matter_module_2_DEVELOPMENT_contdx5_3_12_12_25_backup-Mult_Complex_Infill.ipynb #69941136-7c85-4efc-afa4-68d743a38a63
def image_trim(expanded_matrix, path):
    try:
        image = cv2.imread(path)
    except cv2.error:
        image = tf.imread(path)
        
    print('Shape of reference image: ', image.shape)
    expanded_matrix__ = expanded_matrix[0:image.shape[0], 0:image.shape[1]]

    #Explicitly tell Python to delete the massive image file as soon as we're done with it:
    del image
    
    return(expanded_matrix__)

# %% ../white_matter_module_2_DEVELOPMENT_contdx5_3_12_12_25_backup-Mult_Complex_Infill.ipynb #ab0fc1ee-faa5-4b8c-a59b-58d60737333d
def tiff_write(x, output_path):
    
    #x = np.load(path)
    #output_path =  (path[:-4]+'.tiff')
    
    with tf.TiffWriter(output_path, bigtiff = True) as tif:
        options = dict(photometric = 'minisblack',
                       compression = "zlib")
        tif.write(x, **options)
    
        print('Written to:' + output_path)

