from skimage import exposure
#import tiffile as tf

# %% ../white_matter_module_2_DEVELOPMENT_contdx5_3_12_12_25_backup-Mult_Complex_Infill.ipynb #2f194108-dbb2-4969-90a8-fd3d0106e583
def img_disp (img_path, annot, l=7, fig_path=None):
    #Level 2 contains a much smaller version of the file than the full-sized ome.tif
    downsampled_img = tf.imread(img_path, level=2)

    #Used to enhance contrast. --We also generally select layer 7 because it generally contains the full image of cells in the tissue sample.
    enhanced_img = exposure.equalize_adapthist(downsampled_img, #[l], 
        clip_limit=0.05 # Adjust this value (e.g., 0.005 to 0.03) for desired effect
    )

    # 1. Plot the original image.
    fig, ax = plt.subplots(figsize=(16, 12)) 
    ax.imshow(enhanced_img, origin="lower")
    # 2. Plot the mask.
    ax.imshow(annot[::4, ::4], origin="lower", alpha=0.3)
    #ax.imshow(annot[::4, ::4], origin="lower", alpha=0.3)

    #Display the figure:
    ax.set_title("Overlay of Mask With Down-Sampled ome.tif File")
    plt.show()

    #Output the  figure if user has provided a path to do so:
    if fig_path != None:
        fig.savefig(fig_path+'Mask_Over_Tissue_Outline.png', dpi=300)
        print('Written to:'+fig_path+'Mask_Over_Tissue_Outline.png')
        

# %% ../white_matter_module_2_DEVELOPMENT_contdx5_3_12_12_25_backup-Mult_Complex_Infill.ipynb #ecf07206-4420-4091-a3f9-ee21bd6c2262
def mk_tiff(exp_bin_df, ref, outf, q_factor=85, factor=400):
    #Make the initial pivot table.
    pivot_table = mk_pivot_table(exp_bin_df, q_factor)
    #Expand the matrix according to the factor provided.
    expanded_matrix = matr_expand(pivot_table, q_factor, factor)
    #And trim to the right size based on the .tiff file provided.
    expanded_matrix__ = image_trim(expanded_matrix, ref)

    plt.imshow(expanded_matrix__[::factor, ::factor], origin="lower")
    plt.colorbar()
    plt.show()
    
    #Write as .tiff file
    tiff_write(expanded_matrix__, (outf+'array_file.tiff'))

    print('[Now generating the image of the final mask overlaid onto morphology...]')

    #And finally call in 'img_disp' to display the mask overlaid onto the morphology:
    img_disp(img_path=ref, annot=expanded_matrix__,
        fig_path=outf)
    

    return()
